// // This comment suggests that the counter will decrement on each clock cycle when the enable signal is low.
module counter(CLK, RST, EN, Q);
input CLK, RST, EN;
output reg [7:0] Q;

always @(posedge CLK or posedge RST) begin
    if (RST)
        Q <= 0;
    else if (EN)
        Q <= Q + 1;
end

endmodule
